B.akb=new A.h6("Koala, yapay zeka destekli bir mekan analiz uygulamas\u0131d\u0131r. Kullan\u0131c\u0131lar soru foto\u011fraf\u0131 \xe7ekerek ad\u0131m ad\u0131m \xe7\xf6z\xfcm alabilir. Uygulama 9 farkl\u0131 bran\u015fta AI destekli \xf6\u011fretim hizmeti sunar.",null)
B.akI=new A.hl("Hesap ve Kay\u0131t",null)
B.aio=new A.dB("Uygulamay\u0131 kullanmak i\xe7in Google veya telefon numaras\u0131 ile hesap olu\u015fturman\u0131z gerekir",null)
B.air=new A.dB("Hesap bilgilerinizin do\u011fru ve g\xfcncel olmas\u0131ndan siz sorumlusunuz",null)
B.aia=new A.dB("Hesab\u0131n\u0131z\u0131n g\xfcvenli\u011finden siz sorumlusunuz",null)
B.akR=new A.hl("Kredi Sistemi",null)
B.ai8=new A.dB("Her yeni kullan\u0131c\u0131ya 10 \xfccretsiz kredi verilir",null)
B.aix=new A.dB("Her mekan analizi 1 kredi harcar",null)
B.aiw=new A.dB("Ek kredi uygulama i\xe7i sat\u0131n alma ile edinilebilir",null)
B.aiv=new A.dB("Sat\u0131n al\u0131nan krediler iade edilemez",null)
B.akJ=new A.hl("Kabul Edilebilir Kullan\u0131m",null)
B.ak8=new A.h6("Uygulamay\u0131 yaln\u0131zca ki\u015fisel mekan analizi ama\xe7l\u0131 kullanabilirsiniz. A\u015fa\u011f\u0131daki davran\u0131\u015flar yasakt\u0131r:",null)
B.aiu=new A.dB("Uygulamay\u0131 k\xf6t\xfcye kullanmak veya ba\u015fkalar\u0131n\u0131n kullan\u0131m\u0131n\u0131 engellemek",null)
B.ain=new A.dB("Otomatik botlar veya scraper kullanmak",null)
B.aiq=new A.dB("Uygulamay\u0131 s\u0131nav s\u0131ras\u0131nda kopya \xe7ekmek i\xe7in kullanmak",null)
B.aik=new A.dB("Yasalara ayk\u0131r\u0131 i\xe7erik g\xf6ndermek",null)
B.akK=new A.hl("Fikri M\xfclkiyet",null)
B.akd=new A.h6("Uygulama ve i\xe7eri\u011fi Evlumba Software'a aittir. AI taraf\u0131ndan \xfcretilen \xe7\xf6z\xfcmler e\u011fitim ama\xe7l\u0131d\u0131r ve do\u011frulu\u011fu garanti edilmez.",null)
B.akG=new A.hl("Sorumluluk S\u0131n\u0131rlamas\u0131",null)
B.akm=new A.h6('Koala bir mekan analiz asistan\u0131d\u0131r, profesyonel i\xe7 mimar\u0131n yerini almaz. AI \xf6nerilerinin do\u011frulu\u011fu garanti edilmez. Uygulama "oldu\u011fu gibi" sunulur.',null)
B.akO=new A.hl("De\u011fi\u015fiklikler",null)
B.ake=new A.h6("Bu ko\u015fullar\u0131 zaman zaman g\xfcncelleyebiliriz. \xd6nemli de\u011fi\u015fikliklerde uygulama i\xe7i bildirim yapaca\u011f\u0131z.",null)
B.akl=new A.h6("Kullan\u0131m ko\u015fullar\u0131yla ilgili sorular\u0131n\u0131z i\xe7in:\nE-posta: info@evlumba.com\nWeb: evlumba.com\nGeli\u015ftirici: Evlumba Software",null)
